    private void showTasbihCounterPage() {
        JPanel panel = new JPanel(new GridLayout(3, 1, 10, 10));

        JLabel tasbihLabel = new JLabel("Tasbih Count: 0", JLabel.CENTER);
        tasbihLabel.setFont(new Font("Arial", Font.PLAIN, 40));

        TasbihCounter tasbihCounter = new TasbihCounter();

        JButton incrementButton = new JButton("Increment");
        incrementButton.setPreferredSize(new Dimension(50, 25)); // Smaller button
        JButton resetButton = new JButton("Reset");
        resetButton.setPreferredSize(new Dimension(50, 25)); // Smaller button

        incrementButton.addActionListener(e -> {
            tasbihCounter.increment();
            tasbihLabel.setText("Tasbih Count: " + tasbihCounter.getCount());
        });

        resetButton.addActionListener(e -> {
            tasbihCounter.reset();
            tasbihLabel.setText("Tasbih Count: " + tasbihCounter.getCount());
        });

        JButton backButton = new JButton("Back");
        backButton.setPreferredSize(new Dimension(80, 25)); // Smaller button
        backButton.setBackground(Color.BLACK);
        backButton.setForeground(Color.WHITE);
        backButton.addActionListener(e -> showNavigationPage()); // Back button functionality

        panel.add(tasbihLabel);
        panel.add(incrementButton);
        panel.add(resetButton);
        panel.add(backButton);

        setContentPane(panel);
        revalidate();
        repaint();
    }

    static class TasbihCounter {
        private int count = 0;

        public void increment() {
            count++;
        }

        public void reset() {
            count = 0;
        }

        public int getCount() {
            return count;
        }
    }

